using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.Save { public class LearningCardUnlockBinder:MonoBehaviour { [SerializeField] SaveManager saveManager; [SerializeField] GoalManager goalManager; [SerializeField] StageManager stageManager; bool done; void Awake(){ saveManager??=FindAnyObjectByType<SaveManager>(); goalManager??=FindAnyObjectByType<GoalManager>(); stageManager??=FindAnyObjectByType<StageManager>(); } void OnEnable(){ if(goalManager!=null) goalManager.OnStageCleared+=Handle; } void OnDisable(){ if(goalManager!=null) goalManager.OnStageCleared-=Handle; } public void ResetUnlockFlag()=>done=false; void Handle(){ if(done||saveManager==null||stageManager?.CurrentStage==null) return; var id=stageManager.CurrentStage.LearningCardId; if(string.IsNullOrWhiteSpace(id)) return; saveManager.UnlockLearningCardAndSave(id); done=true; } } }
